patterns.template:
// BAD: key={index}
items.map((item, index) => <Item key={index} />)

// GOOD: key={item.id}
items.map(item => <Item key={item.id} />)

// If no ID, generate one at creation time:
const newItem = { id: crypto.randomUUID(), ...data };

// BAD: runs every render
useEffect(() => { fetchData(); });

// GOOD: runs once on mount
useEffect(() => { fetchData(); }, []);

// GOOD: runs when dependency changes
useEffect(() => { fetchData(id); }, [id]);

// BAD: derived state from props
function UserGreeting({ user }) {
  const [name, setName] = useState(user.name); // Stale!
  return <h1>{name}</h1>;
}

// GOOD: compute directly from props
function UserGreeting({ user }) {
  const displayName = user.name.toUpperCase(); // Always fresh
  return <h1>{displayName}</h1>;
}

// Exception: only use state for props as initial values
function EditableField({ initialValue }) {
  const [value, setValue] = useState(initialValue);
  // User edits diverge from initial value intentionally
}

// BAD: direct DOM manipulation
document.getElementById('title').textContent = 'Hello';
document.querySelector('.list').innerHTML = '<li>item</li>';

// GOOD: use React state and refs
const [title, setTitle] = useState('Hello');
const listRef = useRef<HTMLUListElement>(null);
return (
  <>
    <h1>{title}</h1>
    <ul ref={listRef}>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>
  </>
);

// BAD: unsanitized HTML
<div dangerouslySetInnerHTML={{ __html: userInput }} />

// GOOD: sanitize with DOMPurify
import DOMPurify from 'dompurify';
<div dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(userInput) }} />

// BETTER: use a markdown renderer or structured content
import ReactMarkdown from 'react-markdown';
<ReactMarkdown>{userContent}</ReactMarkdown>

// BAD: prop drilling through intermediate components
<App theme={theme}>
  <Layout theme={theme}>
    <Sidebar theme={theme}>
      <NavItem theme={theme} /> {/* Only NavItem needs theme */}
    </Sidebar>
  </Layout>
</App>

// GOOD: use context
const ThemeContext = createContext<Theme>(defaultTheme);

// Provider at top:
<ThemeContext.Provider value={theme}><App /></ThemeContext.Provider>

// Consumer where needed:
function NavItem() {
  const theme = useContext(ThemeContext);
}

// ALSO GOOD: composition
<Layout sidebar={<Sidebar><NavItem theme={theme} /></Sidebar>} />

// BAD: side effect during render
function UserProfile({ id }) {
  fetch(`/api/users/${id}`); // Runs EVERY render!
  const data = localStorage.getItem('user'); // SSR unsafe!
}

// GOOD: side effect in useEffect
function UserProfile({ id }) {
  const [data, setData] = useState(null);
  useEffect(() => {
    fetch(`/api/users/${id}`).then(r => r.json()).then(setData);
  }, [id]);
}

// BAD: hook inside condition
if (isLoggedIn) {
  const [user, setUser] = useState(null); // Breaks Rules of Hooks!
}

// GOOD: always call, conditionally use
const [user, setUser] = useState<User | null>(null);
useEffect(() => {
  if (isLoggedIn) fetchUser().then(setUser);
}, [isLoggedIn]);

// ALSO GOOD: split into a separate component
{isLoggedIn && <AuthenticatedSection />}

// BAD: new object every render
<Avatar style={{ width: 50, height: 50 }} />
<Select options={[{ value: 'a' }, { value: 'b' }]} />

// GOOD: hoist to module scope (static values)
const avatarStyle = { width: 50, height: 50 } as const;
const options = [{ value: 'a' }, { value: 'b' }] as const;

// GOOD: useMemo for dynamic values
const style = useMemo(() => ({ width: size, height: size }), [size]);

// BAD: unhandled error crashes entire app
<App>
  <DataComponent /> {/* If this throws, entire app crashes */}
</App>

// GOOD: error boundary around risky components
<App>
  <ErrorBoundary fallback={<ErrorFallback />}>
    <DataComponent />
  </ErrorBoundary>
</App>

// In Next.js App Router, use error.tsx for route-level error boundaries
